      },
    },
  },
  {
    $project:
      {
        date: "$_id.date",
        clientId: "$_id.clientId",
        userId: "$_id.userId",
				source: "$_id.generateSource",
        total: "$total",
        answered: "$answered",
				tx_consumed: 1
      },
  },
]

